import{_ as s,o as a,c as t,ai as e}from"./chunks/framework.CaiDwmc7.js";const b=JSON.parse('{"title":"Animation System","description":"Harmonica spring physics animations — progress bars, story pop effects, log slide-ins, and continuous animations.","frontmatter":{"title":"Animation System","description":"Harmonica spring physics animations — progress bars, story pop effects, log slide-ins, and continuous animations.","outline":[2,3]},"headers":[],"relativePath":"cli/animation.md","filePath":"cli/animation.md","lastUpdated":1772487797000}'),i={name:"cli/animation.md"};function r(p,n,l,d,o,c){return a(),t("div",null,[...n[0]||(n[0]=[e(`<h1 id="animation-system" tabindex="-1">Animation System <a class="header-anchor" href="#animation-system" aria-label="Permalink to “Animation System”">​</a></h1><p>All animations are driven by a 100ms tick (<code>TickMsg</code>) and use Harmonica spring physics for organic motion.</p><h2 id="spring-configuration" tabindex="-1">Spring Configuration <a class="header-anchor" href="#spring-configuration" aria-label="Permalink to “Spring Configuration”">​</a></h2><table tabindex="0"><thead><tr><th>Animation</th><th>Stiffness</th><th>Damping</th><th>FPS</th><th>Initial</th><th>Target</th><th>Character</th></tr></thead><tbody><tr><td>Progress Bar</td><td>6.0</td><td>0.7</td><td>60</td><td>0.0</td><td><code>ProgressPercent()</code></td><td>Snappy, slight overshoot</td></tr><tr><td>Story Pop</td><td>8.0</td><td>0.5</td><td>60</td><td>0.3 (start scale)</td><td>1.0 (normal)</td><td>Very bouncy</td></tr><tr><td>Log Slide-In</td><td>5.0</td><td>0.8</td><td>60</td><td>20.0 (x-offset)</td><td>0.0 (settled)</td><td>Smooth, minimal overshoot</td></tr><tr><td>Ray Length</td><td>4.0</td><td>0.3</td><td>60</td><td><code>{6,5,4,3}</code></td><td>Random 4–8</td><td>Bouncy, organic</td></tr></tbody></table><h2 id="animation-update-loop-per-100ms-tick" tabindex="-1">Animation Update Loop (per 100ms tick) <a class="header-anchor" href="#animation-update-loop-per-100ms-tick" aria-label="Permalink to “Animation Update Loop (per 100ms tick)”">​</a></h2><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>TickMsg received</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── 1. Splash.Tick()                 (if splash active — advance mesh/particles)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── 2. Prism.Tick()                  (advance 3D rotation)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── 3. PrismTick++ → PrismFrame      (every 3 ticks → cycle 4 spectrum colors)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── 4. ShimmerPhase += 0.08          (sine wave, wraps at 2π)</span></span>
<span class="line"><span>    │       └── prism body brightness oscillation</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── 5. RayLengths lerp toward targets (linear 0.1 rate, re-target randomly)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    └── 6. Broadcast to all plugins:</span></span>
<span class="line"><span>            ├── Spectrum:</span></span>
<span class="line"><span>            │   ├── Spinner.Update()              (advance frame)</span></span>
<span class="line"><span>            │   ├── ProgressSpring.Update()       (pos, vel → target)</span></span>
<span class="line"><span>            │   ├── StoryPopSpring.Update()       (per-story scale → 1.0)</span></span>
<span class="line"><span>            │   │       └── cleanup when |scale - 1.0| &lt; 0.01</span></span>
<span class="line"><span>            │   ├── PulsePhase += 0.15            (sine wave, wraps at 2π)</span></span>
<span class="line"><span>            │   │       └── active story icon brightness</span></span>
<span class="line"><span>            │   ├── LogSlideSpring.Update()       (per-entry offset → 0.0)</span></span>
<span class="line"><span>            │   └── RaySpring.Update()            (per-ray length → target)</span></span>
<span class="line"><span>            └── All other plugins (no-op for most)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br></div></div><h2 id="continuous-animations" tabindex="-1">Continuous Animations <a class="header-anchor" href="#continuous-animations" aria-label="Permalink to “Continuous Animations”">​</a></h2><table tabindex="0"><thead><tr><th>Animation</th><th>Increment/Tick</th><th>Full Cycle</th><th>Effect</th></tr></thead><tbody><tr><td>Pulse</td><td>+0.15 rad</td><td>~4.2 seconds</td><td>Active story icon brightness oscillation (0.2 → 1.0)</td></tr><tr><td>Shimmer</td><td>+0.08 rad</td><td>~7.85 seconds</td><td>Prism body brightness modulation (0.85 → 1.0)</td></tr><tr><td>Prism Frame</td><td>+1 every 300ms</td><td>1.2 seconds</td><td>4-color spectrum rotation on text prism</td></tr><tr><td>3D Rotation</td><td>0.6 rad/sec Y-axis</td><td>~10.5 seconds</td><td>Full rotation of 3D prism model</td></tr></tbody></table>`,8)])])}const h=s(i,[["render",r]]);export{b as __pageData,h as default};
